import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
      }
    }
  }, [editingId, allQuestions]);

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Act as a world-class Anatomy Professor and Elite Web Data Architect.

        TASK: Extract anatomical quiz questions from the provided input. 
        The input might be raw text, a messy copy-paste from a website, or even full HTML code.

        SPECIAL INSTRUCTION FOR HTML:
        If the input contains HTML code, parse it carefully. 
        CRITICAL: Look for <img> tags. Extract the 'src' attribute of any image that appears related to the anatomical question or diagram and put it in "questionImage".

        INPUT CONTENT: """${rawInput}"""

        OUTPUT SPECIFICATIONS (JSON):
        1. "questionText": The main question using clean HTML (<b> for terms).
        2. "answerText": The correct answer.
        3. "explanation": A detailed clinical explanation in HTML (use <ul>/<li>).
        4. "options": Exactly 4 possible answers (including the correct one).
        5. "category": The specific chapter or system (e.g., "Chapter 7: Axial Skeleton").
        6. "questionImage": The FULL URL of an image if found in the input (especially if in an <img> tag).

        Return ONLY a valid JSON object.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      const result = JSON.parse(response.text);
      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || ''
      });
      setShowPreview(true);
      setRawInput('');
    } catch (error) {
      console.error("AI Architect Error:", error);
      alert("System was unable to architect this content. Please try again with more descriptive text or HTML.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 space-y-12 pb-48 animate-in fade-in duration-1000">

      {/* PHASE 1: THE COMMAND CENTER */}
      {!showPreview && (
        <div className="relative max-w-5xl mx-auto pt-10">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full bg-blue-500/5 rounded-full blur-[120px] pointer-events-none"></div>

          <div className="relative bg-slate-900 rounded-[3rem] shadow-[0_40px_100px_rgba(0,0,0,0.4)] border border-slate-800/50 backdrop-blur-xl overflow-hidden">
            <div className="p-8 md:p-16 space-y-12">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
                <div className="space-y-4">
                  <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl shadow-2xl flex items-center justify-center text-white ring-4 ring-blue-500/20">
                      <Sparkles size={28} className="animate-pulse" />
                    </div>
                    <div>
                      <h2 className="text-4xl md:text-6xl font-black text-white tracking-tighter">
                        Smart <span className="text-blue-500">Extractor</span>
                      </h2>
                      <p className="text-slate-400 font-bold text-xs uppercase tracking-[0.4em] mt-1">Extract from Raw Text or HTML Code</p>
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-3">
                   <div className="flex flex-col items-end">
                      <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Web Scraping Active</span>
                      <span className="text-xs font-bold text-white">Gemini 3 Pro</span>
                   </div>
                   <div className="w-10 h-10 rounded-full border-2 border-slate-700 flex items-center justify-center">
                      <div className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></div>
                   </div>
                </div>
              </div>

              <div className="relative group">
                <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2rem] blur opacity-10 group-hover:opacity-25 transition duration-500"></div>
                <div className="relative">
                  <textarea
                    value={rawInput}
                    onChange={(e) => setRawInput(e.target.value)}
                    className="w-full h-72 p-10 bg-slate-950/50 text-blue-50 rounded-[2.5rem] border-2 border-slate-800/50 focus:border-blue-500 outline-none font-medium text-2xl placeholder:text-slate-700 transition-all shadow-inner resize-none custom-scrollbar"
                    placeholder="Paste website HTML, question text, or image links here..."
                  />
                  <div className="absolute top-0 right-0 p-8 text-slate-800 pointer-events-none">
                    <Binary size={120} />
                  </div>
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-6 mt-8">
                  <div className="flex items-center gap-8">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Image Scraper</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2">
                        <ImageIcon size={14} className="text-blue-500" /> Automatic Link Discovery
                      </span>
                    </div>
                    <div className="w-px h-8 bg-slate-800"></div>
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Target Vault</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2">
                        <Database size={14} className="text-indigo-500" /> Local Storage v4
                      </span>
                    </div>
                  </div>

                  <button 
                    onClick={processEverythingWithAI}
                    disabled={isAiLoading || !rawInput.trim()}
                    className="w-full md:w-auto flex items-center justify-center gap-4 px-12 py-6 bg-blue-600 text-white rounded-[2rem] font-black text-2xl hover:bg-blue-500 hover:-translate-y-1 transition-all shadow-[0_20px_50px_rgba(37,99,235,0.3)] disabled:opacity-20 active:scale-95 group relative overflow-hidden"
                  >
                    {isAiLoading ? (
                      <Loader2 className="animate-spin" size={28} />
                    ) : (
                      <Wand2 size={28} className="group-hover:rotate-12 transition-transform" />
                    )}
                    <span>{isAiLoading ? 'Analyzing HTML...' : 'Extract & Build'}</span>
                  </button>
                </div>
              </div>
            </div>

            <div className="h-2 bg-gradient-to-r from-blue-600 via-indigo-600 to-blue-600"></div>
          </div>
        </div>
      )}

      {/* PHASE 2: THE PUBLISHING STAGE */}
      {showPreview && (
        <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-700">

          <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-6 rounded-[2rem] border border-slate-200 shadow-xl">
            <div className="flex items-center gap-4">
              <button 
                onClick={resetSystem} 
                className="p-4 rounded-2xl bg-slate-50 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all shadow-sm"
                title="Discard"
              >
                <RotateCcw size={24} />
              </button>
              <div className="h-10 w-px bg-slate-100"></div>
              <div>
                <h3 className="text-lg font-black text-slate-900 leading-tight">Reviewing Draft</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Pending Sync to Vault</p>
              </div>
            </div>

            <div className="flex items-center gap-4 w-full md:w-auto">
              <button 
                onClick={() => setIsManualEdit(!isManualEdit)} 
                className={`flex-1 md:flex-none px-8 py-4 rounded-2xl font-black text-sm transition-all flex items-center justify-center gap-3 border-2 ${isManualEdit ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-500'}`}
              >
                {isManualEdit ? <Eye size={20} /> : <Edit3 size={20} />}
                {isManualEdit ? 'Preview Card' : 'Manual Refine'}
              </button>

              <button 
                onClick={handleGlobalPublish}
                className="flex-1 md:flex-none px-10 py-4 bg-emerald-600 text-white font-black text-sm uppercase tracking-[0.2em] rounded-2xl shadow-[0_15px_40px_rgba(16,185,129,0.3)] hover:bg-emerald-500 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 active:scale-95"
              >
                <Send size={18} />
                Global Publish
              </button>
            </div>
          </div>

          <div className="grid lg:grid-cols-12 gap-10">
            <div className="lg:col-span-8">
              {isManualEdit ? (
                <div className="bg-white rounded-[3rem] p-10 md:p-14 border border-slate-100 shadow-2xl space-y-10">
                  <div className="grid gap-8">
                    <div className="space-y-3">
                      <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                        <Layers size={14} className="text-blue-500" /> Section Category
                      </div>
                      <input 
                        type="text" 
                        value={formData.category} 
                        onChange={e => setFormData({...formData, category: e.target.value})}
                        className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold text-slate-800 outline-none focus:border-blue-500 transition-all"
                      />
                    </div>

                    <div className="space-y-3">
                      <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                        <FileCode size={14} className="text-blue-500" /> Question Source
                      </div>
                      <textarea 
                        value={formData.questionText} 
                        onChange={e => setFormData({...formData, questionText: e.target.value})}
                        className="w-full h-44 p-6 bg-slate-50 border-2 border-slate-100 rounded-3xl font-mono text-sm text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all"
                      />
                    </div>

                    <div className="grid sm:grid-cols-2 gap-6">
                      {formData.options.map((opt, i) => (
                        <div key={i} className="space-y-2">
                          <label className="text-[9px] font-black text-slate-300 uppercase tracking-widest px-2">Option {String.fromCharCode(65 + i)}</label>
                          <input 
                            type="text" 
                            value={opt} 
                            onChange={e => {
                              const newOpts = [...formData.options];
                              newOpts[i] = e.target.value;
                              setFormData({...formData, options: newOpts});
                            }}
                            className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold text-slate-700 outline-none focus:border-blue-500 transition-all"
                          />
                        </div>
                      ))}
                    </div>

                    <div className="space-y-3">
                      <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                        <Beaker size={14} className="text-blue-500" /> Scientific Rationale
                      </div>
                      <textarea 
                        value={formData.explanation} 
                        onChange={e => setFormData({...formData, explanation: e.target.value})}
                        className="w-full h-40 p-6 bg-slate-50 border-2 border-slate-100 rounded-3xl font-mono text-sm text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all"
                      />
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-white rounded-[4rem] shadow-[0_50px_100px_rgba(0,0,0,0.08)] border border-slate-100 overflow-hidden flex flex-col group transition-all duration-500 hover:shadow-[0_60px_120px_rgba(0,0,0,0.1)]">
                  <div className="bg-slate-900 p-8 flex justify-between items-center">
                    <span className="text-[11px] font-black text-blue-400 uppercase tracking-[0.4em] font-mono flex items-center gap-2">
                       <ShieldCheck size={14} /> Master Data Frame
                    </span>
                    <div className="flex items-center gap-2">
                       <span className="w-2 h-2 rounded-full bg-slate-700"></span>
                       <span className="w-2 h-2 rounded-full bg-slate-700"></span>
                       <span className="w-2 h-2 rounded-full bg-slate-700"></span>
                    </div>
                  </div>

                  <div className="p-10 md:p-20 space-y-14">
                    <div className="space-y-8">
                       <div className="px-5 py-2 bg-blue-50 rounded-full w-fit border border-blue-100">
                          <span className="text-xs font-black text-blue-600 uppercase tracking-widest">{formData.category}</span>
                       </div>

                       {formData.questionImage && (
                         <div className="w-full flex justify-center mb-8">
                           <div className="relative group/img">
                             <div className="absolute -inset-2 bg-blue-500/20 rounded-3xl blur-xl opacity-0 group-hover/img:opacity-100 transition duration-500"></div>
                             <img 
                               src={formData.questionImage} 
                               alt="Extracted" 
                               className="relative max-h-80 rounded-2xl border-2 border-slate-100 shadow-2xl object-contain"
                               onError={(e) => (e.currentTarget.style.display = 'none')}
                             />
                           </div>
                         </div>
                       )}

                       <h3 className="text-4xl md:text-5xl font-black text-slate-900 leading-tight tracking-tight" dangerouslySetInnerHTML={{ __html: formData.questionText }} />
                    </div>

                    <div className="grid gap-4">
                      {formData.options.map((opt, i) => (
                        <div key={i} className={`p-6 rounded-[2rem] border-2 flex items-center gap-6 transition-all duration-300 ${opt === formData.answerText ? 'border-emerald-500 bg-emerald-50/30' : 'border-slate-50 bg-slate-50/50 text-slate-400'}`}>
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-2xl ${opt === formData.answerText ? 'bg-emerald-600 text-white' : 'bg-white border border-slate-100 text-slate-300 shadow-sm'}`}>
                            {String.fromCharCode(65 + i)}
                          </div>
                          <div className="font-bold text-2xl text-slate-800" dangerouslySetInnerHTML={{ __html: opt }} />
                          {opt === formData.answerText && <CheckCircle2 className="ml-auto text-emerald-600" size={32} />}
                        </div>
                      ))}
                    </div>

                    <div className="bg-slate-900 rounded-[3rem] p-12 text-white/90 relative overflow-hidden">
                       <div className="absolute top-0 right-0 p-10 text-white/5 rotate-12">
                          <Globe size={160} />
                       </div>
                       <div className="relative z-10 space-y-6">
                          <div className="flex items-center gap-3">
                             <div className="p-2 bg-blue-600 rounded-lg">
                                <Zap size={18} className="text-white" />
                             </div>
                             <span className="text-sm font-black uppercase tracking-[0.2em] text-blue-400">Clinical Correlation</span>
                          </div>
                          <div className="text-xl leading-relaxed font-medium prose prose-invert opacity-90" dangerouslySetInnerHTML={{ __html: formData.explanation }} />
                       </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="lg:col-span-4 space-y-10">
              <div className="bg-white rounded-[2.5rem] p-10 border border-slate-100 shadow-2xl space-y-12 sticky top-32">
                <div className="space-y-8">
                  <h4 className="font-black text-slate-900 uppercase tracking-[0.2em] text-[10px] border-b border-slate-50 pb-6 flex items-center gap-2">
                    <ImageIcon size={16} className="text-blue-500" /> Visual Assets
                  </h4>

                  <div className="space-y-8">
                    <div className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Resource Layer A (Question)</label>
                      <div className="relative group/input">
                        <ImageIcon size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within/input:text-blue-500 transition-colors" />
                        <input 
                          type="url" 
                          value={formData.questionImage}
                          onChange={e => setFormData({...formData, questionImage: e.target.value})}
                          className="w-full pl-14 pr-6 py-5 rounded-2xl bg-slate-50 border-2 border-slate-50 text-xs font-bold text-slate-600 focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
                          placeholder="Image URL source..."
                        />
                      </div>
                    </div>
                    <div className="space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Resource Layer B (Answer)</label>
                      <div className="relative group/input">
                        <ImageIcon size={18} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within/input:text-blue-500 transition-colors" />
                        <input 
                          type="url" 
                          value={formData.answerImage}
                          onChange={e => setFormData({...formData, answerImage: e.target.value})}
                          className="w-full pl-14 pr-6 py-5 rounded-2xl bg-slate-50 border-2 border-slate-50 text-xs font-bold text-slate-600 focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
                          placeholder="Detailed insight URL..."
                        />
                      </div>
                    </div>
                  </div>
                </div>

                <div className="p-8 bg-gradient-to-br from-slate-900 to-slate-950 rounded-[2rem] text-white space-y-6 shadow-2xl relative overflow-hidden">
                   <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/10 rounded-full blur-3xl -mr-16 -mt-16"></div>
                   <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                        <Server size={22} />
                      </div>
                      <div>
                        <span className="block font-black uppercase text-xs tracking-widest">AI Audit</span>
                        <span className="text-[10px] text-blue-400 font-bold">Standardized 100%</span>
                      </div>
                   </div>
                   <div className="space-y-3 pt-2">
                      <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-500">
                        <span>Terminology</span>
                        <span className="text-blue-400">PASSED</span>
                      </div>
                      <div className="h-1 bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-blue-500 w-full animate-pulse"></div>
                      </div>
                   </div>
                </div>

                <div className="flex items-start gap-4 p-6 bg-blue-50 rounded-[1.5rem] border border-blue-100">
                   <Info className="text-blue-600 shrink-0 mt-1" size={20} />
                   <p className="text-[11px] leading-relaxed text-blue-800 font-bold uppercase tracking-tight">
                     Data published globally will be automatically mirrored to your local vault for offline study.
                   </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionBuilder;

import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
      }
    }
  }, [editingId, allQuestions]);

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      const prompt = isUrl 
        ? `I am providing a URL: "${rawInput.trim()}". 
           Use your Google Search tool to access this URL and extract a high-quality anatomical quiz question from its content.

           OUTPUT SPECIFICATIONS (JSON):
           1. "questionText": The main question using clean HTML (<b> for terms).
           2. "answerText": The correct answer.
           3. "explanation": A detailed clinical explanation in HTML (use <ul>/<li>).
           4. "options": Exactly 4 possible answers (including the correct one).
           5. "category": The specific chapter or system (e.g., "Chapter 7: Axial Skeleton").
           6. "questionImage": The FULL URL of an image if found on the page.`
        : `Act as a world-class Anatomy Professor and Elite Web Data Architect.
           TASK: Extract anatomical quiz questions from the provided input. 
           The input might be raw text, a messy copy-paste from a website, or even full HTML code.

           SPECIAL INSTRUCTION FOR HTML:
           If the input contains HTML code, parse it carefully. 
           CRITICAL: Look for <img> tags. Extract the 'src' attribute of any image that appears related to the anatomical question or diagram and put it in "questionImage".

           INPUT CONTENT: """${rawInput}"""

           OUTPUT SPECIFICATIONS (JSON):
           1. "questionText": The main question using clean HTML (<b> for terms).
           2. "answerText": The correct answer.
           3. "explanation": A detailed clinical explanation in HTML (use <ul>/<li>).
           4. "options": Exactly 4 possible answers (including the correct one).
           5. "category": The specific chapter or system (e.g., "Chapter 7: Axial Skeleton").
           6. "questionImage": The FULL URL of an image if found in the input (especially if in an <img> tag).`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || ''
      });
      setShowPreview(true);
      setRawInput('');
    } catch (error) {
      console.error("AI Architect Error:", error);
      alert("System was unable to architect this content. If you provided a URL, ensure it is accessible.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 space-y-12 pb-48 animate-in fade-in duration-1000">

      {/* PHASE 1: THE COMMAND CENTER */}
      {!showPreview && (
