export default QuestionBuilder;

import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    // Check if we have an API key selected if we are going to use a Pro model
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      const prompt = isUrl 
        ? `Navigate to this URL: "${rawInput.trim()}". 
           Task: Use your search grounding to extract or generate a high-quality medical/anatomical quiz question based ON THE CONTENT of this specific page.

           Strict JSON Format required:
           {
             "questionText": "Main question (use <b> for terms)",
             "answerText": "Correct answer",
             "explanation": "Detailed rationale (HTML)",
             "options": ["Opt1", "Opt2", "Opt3", "Opt4"],
             "category": "Topic Name",
             "questionImage": "Image URL from the page if relevant"
           }`
        : `Act as a world-class Anatomy Professor. Extract an anatomical quiz question from this input:
           """${rawInput}"""

           Return JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          // Note: When using googleSearch, responseMimeType might be ignored by the model's grounding process,
          // so we handle the text output manually to find the JSON block.
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      // Extract sources from grounding metadata if available
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      // Robust JSON Extraction (handles text surrounding the JSON block)
      let rawText = response.text || "";
      let jsonPart = rawText;
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        jsonPart = jsonMatch[0];
      }

      const result = JSON.parse(jsonPart);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        options: Array.isArray(result.options) ? result.options : []
      });

      setShowPreview(true);
      setRawInput('');
    } catch (error: any) {
      console.error("AI Architect Error:", error);

      // Handle the specific error mentioned in rules
      if (error.message?.includes("Requested entity was not found")) {
        alert("API Key configuration error. Please select a valid paid API key.");
        if (window.aistudio) await window.aistudio.openSelectKey();
      } else {
