import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { Shuffle, RotateCcw, Image as ImageIcon, CircleAlert, Eye, EyeOff, ChevronLeft, ChevronRight, Volume2, VolumeX, Lightbulb, Filter, Check, X, ChevronDown, Pencil } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, activeType } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = () => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(!isFlipped);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const currentCard = deck[currentIndex];

  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  return (
    <div className="flex flex-col items-center justify-center max-w-3xl mx-auto w-full px-4 py-8">
      <div className="w-full flex flex-col md:flex-row justify-between items-center mb-6 gap-4 relative z-20">
        <span className="text-xs font-bold text-slate-500 uppercase bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm">
          {deck.length > 0 ? `Card ${currentIndex + 1} / ${deck.length}` : '0 Cards'}
        </span>

        <div className="flex items-center gap-2">
          {currentCard && (
            <button 
              onClick={() => onEdit(currentCard.id)}
              className="flex items-center gap-2 px-3 py-1.5 text-xs font-bold text-amber-600 bg-amber-50 border border-amber-200 rounded-lg hover:bg-amber-100 transition-colors"
            >
              <Pencil size={14} /> Edit This
            </button>
          )}

          <div className="relative">
            <Button 
              variant="ghost" 
              onClick={() => setIsFilterOpen(!isFilterOpen)}
              className={`flex items-center gap-2 text-xs font-bold rounded-lg border ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200'}`}
            >
              <Filter size={14} />
              {selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'Filter'}
              <ChevronDown size={12} className={`transition-transform ${isFilterOpen ? 'rotate-180' : ''}`} />
            </Button>

            {isFilterOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                <div className="absolute right-0 top-full mt-2 w-64 bg-white border border-slate-200 rounded-xl shadow-xl z-20 overflow-hidden flex flex-col max-h-[60vh]">
                  <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                    <span className="text-xs font-bold text-slate-500 uppercase">Topics</span>
                    <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-red-500">Clear</button>
                  </div>
                  <div className="overflow-y-auto p-2">
                    {categories.map(cat => (
                      <label key={cat} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 text-blue-600 rounded"
                          checked={selectedCategories.includes(cat)}
                          onChange={() => toggleCategory(cat)}
                        />
                        <span className="text-sm font-medium">{cat}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          <Button variant="ghost" onClick={() => {
            const shuffled = [...deck].sort(() => Math.random() - 0.5);
            setDeck(shuffled);
            setCurrentIndex(0);
          }} className="text-xs font-bold text-slate-500">
            <Shuffle size={14} className="mr-1" /> Shuffle
          </Button>
        </div>
      </div>

      {deck.length > 0 ? (
        <div className="relative w-full aspect-[16/9] cursor-pointer perspective-1000 z-10 group" onClick={flipCard}>
          <div className={`w-full h-full relative transform-style-3d transition-all duration-500 group-hover:scale-[1.015] ${isFlipped ? 'rotate-y-180' : ''}`}>

            <div className="absolute inset-0 w-full h-full bg-white rounded-xl shadow-md border border-slate-200 backface-hidden flex flex-col overflow-hidden group-hover:shadow-2xl transition-shadow duration-500">
              <div className="px-6 pt-6 flex justify-between items-start">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider bg-slate-50 px-2 py-0.5 rounded border border-slate-100">
                  {currentCard.category}
                </span>
                <button 
                  onClick={(e) => speak(stripHtml(currentCard.questionText), currentCard.id, 'question', e)}
                  className={`p-2 rounded-full transition-all ${isSpeaking && activeType === 'question' ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
                >
                  <Volume2 size={18} />
                </button>
              </div>
              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto">
                {currentCard.questionImage && !imgError && (
                  <img 
                    src={currentCard.questionImage} 
                    className="max-h-40 mb-4 rounded border shadow-sm"
                    onError={() => setImgError(true)}
                  />
                )}
                <div 
                  className="text-xl md:text-2xl font-bold text-center text-slate-800 leading-relaxed"
                  dangerouslySetInnerHTML={{ __html: currentCard.questionText }}
                />
              </div>
              <div className="h-8 text-center text-[10px] font-bold text-slate-300 uppercase tracking-widest">Click to reveal</div>
            </div>

            <div className="absolute inset-0 w-full h-full bg-slate-800 rounded-xl shadow-md border border-slate-700 backface-hidden rotate-y-180 flex flex-col overflow-hidden group-hover:shadow-2xl transition-shadow duration-500">
              <div className="px-6 pt-6 flex justify-between items-center">
                <span className="text-xs font-bold uppercase text-blue-400">Answer</span>
                <button 
                  onClick={(e) => speak(stripHtml(currentCard.answerText), currentCard.id, 'answer', e)}
                  className={`p-2 rounded-full transition-all ${isSpeaking && activeType === 'answer' ? 'text-blue-400 bg-white/10' : 'text-slate-500 hover:text-blue-400'}`}
                >
                  <Volume2 size={18} />
                </button>
              </div>
              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto">
                {currentCard.answerImage && !ansImgError && (
                  <img 
                    src={currentCard.answerImage} 
                    className="max-h-40 mb-4 rounded border border-slate-600"
                    onError={() => setAnsImgError(true)}
                  />
                )}
                <div 
                  className="text-xl md:text-3xl font-bold text-center text-white leading-relaxed mb-4"
                  dangerouslySetInnerHTML={{ __html: currentCard.answerText }}
                />
                {currentCard.explanation && (
                  <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700/50 text-slate-300 text-sm leading-relaxed max-w-lg text-center"
                    dangerouslySetInnerHTML={{ __html: currentCard.explanation }} 
                  />
                )}
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="p-12 bg-white rounded-xl border-2 border-dashed text-center">No cards found.</div>
      )}

      <div className="flex items-center gap-6 mt-8">
        <Button variant="outline" onClick={() => setCurrentIndex(p => Math.max(0, p-1))} disabled={currentIndex === 0} className="w-12 h-12 rounded-full"><ChevronLeft /></Button>
        <Button variant="primary" onClick={flipCard} className="h-12 px-8 rounded-full shadow-lg">
          {isFlipped ? 'Hide' : 'Reveal'}
        </Button>
        <Button variant="secondary" onClick={() => setCurrentIndex(p => Math.min(deck.length-1, p+1))} disabled={currentIndex === deck.length-1} className="w-12 h-12 rounded-full"><ChevronRight /></Button>
      </div>
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle, Terminal
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    // Logic to ensure a valid key is selected for Pro models
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Neural Engine...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Authenticating Secure API Link...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Navigating Web Sources...' : 'Analyzing Anatomical Data...');

      const prompt = isUrl 
        ? `TASK: Web Content Extraction.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE professional anatomical quiz question based exclusively on the content of this page.

           REQUIRED OUTPUT FORMAT (JSON ONLY):
           {
             "questionText": "Clear question using <b> for key terms",
             "answerText": "Precise correct answer",
             "explanation": "Scientific rationale formatted with HTML tags",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "Identify the anatomical system/chapter",
             "questionImage": "Direct URL to a relevant image on the page if found"
           }`
        : `TASK: Text/HTML Synthesis.
           INPUT: """${rawInput}"""
           INSTRUCTION: Extract one anatomical quiz question from the provided input. 

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          // If using URL/Search, responseMimeType is often ignored by the grounding layer
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          // Only provide schema for non-URL as search grounding is less stable with complex configs
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Validating Structured Output...');

      // Grounding Source Extraction
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      // Robust JSON Extraction via Regex (essential for search results which often include fluff)
      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON architecture found in model response.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        // Shuffle options so correct isn't always first if the model was lazy
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Success! Rendering Preview...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Architectural Failure:", error);
      setIsAiLoading(false);

      if (error.message?.includes("Requested entity was not found")) {
        alert("CRITICAL ERROR: A paid API key from a Google Cloud Project is required for web-scraping features. Please select one now.");
        if (window.aistudio) await window.aistudio.openSelectKey();
      } else {
        alert("The AI Architect encountered an error. This usually happens if the URL is blocked or the content is too sparse. Try pasting the text directly.");
      }
    }
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-12 space-y-12 pb-48 animate-in fade-in duration-1000">

      {/* PHASE 1: THE INPUT COMMAND CENTER */}
      {!showPreview && (
        <div className="relative max-w-5xl mx-auto pt-4">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full bg-blue-600/10 rounded-full blur-[160px] pointer-events-none"></div>

          <div className="relative bg-slate-900 rounded-[3.5rem] shadow-[0_40px_100px_rgba(0,0,0,0.5)] border border-slate-800/80 backdrop-blur-2xl overflow-hidden">
            <div className="p-8 md:p-20 space-y-12">

              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10">
                <div className="space-y-4">
                  <div className="flex items-center gap-5">
                    <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl shadow-2xl flex items-center justify-center text-white ring-4 ring-blue-500/20 transform rotate-3">
                      <Zap size={32} className="animate-pulse" />
                    </div>
                    <div>
                      <h2 className="text-4xl md:text-6xl font-black text-white tracking-tighter leading-none">
                        AI <span className="text-blue-500">Architect</span>
                      </h2>
                      <p className="text-slate-500 font-bold text-xs uppercase tracking-[0.4em] mt-3">Professional Data Extraction Suite</p>
                    </div>
                  </div>
                </div>

                <div className="hidden md:flex items-center gap-4 bg-slate-950/50 p-4 rounded-3xl border border-slate-800/50">
                   <div className="flex flex-col items-end">
                      <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">Neural Link: Active</span>
                      <span className="text-xs font-bold text-slate-300">Gemini 3 Pro + Search</span>
                   </div>
                   <div className="w-12 h-12 rounded-2xl border-2 border-slate-800 flex items-center justify-center bg-slate-900 shadow-inner">
                      <div className="w-3 h-3 bg-emerald-500 rounded-full shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-ping"></div>
                   </div>
                </div>
              </div>

              <div className="relative group">
                {isAiLoading && (
                  <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-md rounded-[2.5rem] border-2 border-blue-500/30 animate-in zoom-in-95 duration-300">
                    <div className="relative">
                      <div className="w-24 h-24 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Cpu className="text-blue-400 animate-pulse" size={32} />
                      </div>
                    </div>
                    <div className="mt-8 text-center space-y-3">
                      <p className="text-xl font-black text-white tracking-tight">{loadingStep}</p>
                      <div className="flex items-center gap-2 justify-center">
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></span>
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                      </div>
                    </div>
                  </div>
                )}

                <div className="absolute -inset-2 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2.5rem] blur opacity-10 group-hover:opacity-20 transition duration-1000"></div>

                <div className="relative">
                  <textarea
                    value={rawInput}
                    onChange={(e) => setRawInput(e.target.value)}
                    className="w-full h-80 p-12 bg-slate-950/60 text-blue-50 rounded-[2.5rem] border-2 border-slate-800 focus:border-blue-500 outline-none font-medium text-2xl placeholder:text-slate-700 transition-all shadow-inner resize-none custom-scrollbar"
                    placeholder="Paste URL (e.g. kenhub.com/en/skull) or copy-paste anatomy notes here..."
                  />
                  <div className="absolute bottom-6 right-8 flex items-center gap-2 text-slate-700 font-black text-[10px] uppercase tracking-widest pointer-events-none">
                    <Terminal size={14} /> Neural Input Interface v4.2
                  </div>
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-8 mt-10">
                  <div className="flex items-center gap-10">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Grounding Tool</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2 mt-1">
                        <Globe size={16} className="text-blue-500" /> Web-to-Vault Sync
                      </span>
                    </div>
                    <div className="w-px h-10 bg-slate-800"></div>
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Output Logic</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2 mt-1">
                        <FileCode size={16} className="text-indigo-500" /> Structural JSON
                      </span>
                    </div>
                  </div>

                  <button 
                    onClick={processEverythingWithAI}
                    disabled={isAiLoading || !rawInput.trim()}
                    className="w-full md:w-auto flex items-center justify-center gap-5 px-16 py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-3xl hover:bg-blue-500 hover:-translate-y-2 transition-all shadow-[0_20px_60px_rgba(37,99,235,0.4)] disabled:opacity-20 active:scale-95 group relative overflow-hidden"
                  >
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                    <Wand2 size={36} className="group-hover:rotate-12 transition-transform" />
                    <span>Generate Question</span>
                  </button>
                </div>
              </div>
            </div>

            <div className="h-2.5 bg-gradient-to-r from-blue-600 via-indigo-600 to-blue-600"></div>
          </div>

          <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-8">
             <div className="flex items-start gap-4 p-8 bg-white/5 rounded-3xl border border-slate-200/10">
                <ShieldCheck className="text-blue-500 shrink-0" size={24} />
                <div>
                  <h4 className="text-white font-bold text-sm uppercase tracking-wider mb-2">Verified Content</h4>
                  <p className="text-slate-500 text-xs leading-relaxed">Every question is processed through clinical validation layers to ensure anatomical precision.</p>
