                <Database className="text-indigo-500 shrink-0" size={24} />
                <div>
                  <h4 className="text-white font-bold text-sm uppercase tracking-wider mb-2">Auto-Vaulting</h4>
                  <p className="text-slate-500 text-xs leading-relaxed">Generated data is instantly mirrored to your encrypted local vault for offline study capability.</p>
