             </div>
             <div className="flex items-start gap-4 p-8 bg-white/5 rounded-3xl border border-slate-200/10">
                <Zap className="text-amber-500 shrink-0" size={24} />
                <div>
                  <h4 className="text-white font-bold text-sm uppercase tracking-wider mb-2">Fast Synthesis</h4>
                  <p className="text-slate-500 text-xs leading-relaxed">Gemini 3 Turbo engines synthesize complex clinical scenarios from raw URLs in under 5 seconds.</p>
                </div>
             </div>
          </div>
        </div>
