import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import { AppMode, Question } from './types';
import { questions as importedQuestions } from './data';
import { ShieldCheck, DatabaseZap } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [isSyncing, setIsSyncing] = useState(false);

  // PRIMARY DATA VAULT: Loads user additions and modifications from local storage
  // (Maintained for existing data, even if adding is disabled)
  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Critical: Data Vault Access Denied", e);
      return [];
    }
  });

  // AUTO-PERSISTENCE
  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));

    // UI Feedback for Syncing
    setIsSyncing(true);
    const timer = setTimeout(() => setIsSyncing(false), 1200);
    return () => clearTimeout(timer);
  }, [userVault]);

  const handleDeleteFromVault = (id: string) => {
    if (confirm("Security Alert: This action will permanently wipe this record from the Global Vault. Proceed?")) {
      setUserVault(prev => prev.filter(q => q.id !== id));
    }
  };

  // KNOWLEDGE BASE COMPILER: Merges system data with user-modified and custom data
  const allQuestions = useMemo(() => {
    const vaultMap = new Map(userVault.map(q => [q.id, q]));

    // 1. Process imported questions, replacing them if a 'Vault Version' exists
    const mergedBase = importedQuestions.map(q => vaultMap.get(q.id) || q);

    // 2. Add brand new questions created by the user that don't exist in the base
    const baseIds = new Set(importedQuestions.map(q => q.id));
    const pureAdditions = userVault.filter(q => !baseIds.has(q.id));

    // Return the combined, deduplicated set
    return [...pureAdditions, ...mergedBase];
  }, [userVault]);

  const exportVault = () => {
    const dataStr = JSON.stringify(userVault, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const date = new Date().toISOString().split('T')[0];
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', `ANATOMY_MASTER_VAULT_${date}.json`);
    link.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          setUserVault(prev => {
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q)); // Merge by ID
            return Array.from(currentMap.values());
          });
          alert("Vault Re-Synchronized: Import Successful.");
        }
      } catch (err) {
        alert("Integrity Error: File format corrupted.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900">
      <Header currentMode={currentMode} onModeChange={setCurrentMode} />

      {/* GLOBAL SYNC HUD */}
      <div className={`fixed bottom-12 right-12 z-[100] transition-all duration-700 pointer-events-none ${isSyncing ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0'}`}>
        <div className="bg-slate-950 text-white px-8 py-4 rounded-[2rem] shadow-[0_20px_60px_rgba(0,0,0,0.3)] flex items-center gap-4 border border-slate-800">
          <div className="relative">
            <div className="absolute inset-0 bg-blue-500 rounded-full blur animate-ping opacity-50"></div>
            <DatabaseZap size={20} className="text-blue-400 relative z-10" />
          </div>
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400">Knowledge Locked</span>
            <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Global Vault Synced</span>
          </div>
          <ShieldCheck size={20} className="text-emerald-400 ml-2" />
        </div>
      </div>

      <main className="flex-1 relative">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block py-6' : 'hidden'}>
          <Flashcards data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
          <Quiz data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.LIST ? 'block py-6' : 'hidden'}>
          <QuestionList 
            data={allQuestions} 
            onDelete={handleDeleteFromVault} 
            userQuestions={userVault}
            onExport={exportVault}
            onImport={importVault}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
