                </span>
                <button 
                  onClick={(e) => speak(stripHtml(currentCard.questionText), currentCard.id, 'question', e)}
                  className={`p-2 rounded-full transition-all ${isSpeaking && activeType === 'question' ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
                >
                  <Volume2 size={18} />
                </button>
              </div>
              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto">
                {currentCard.questionImage && !imgError && (
                  <img 
                    src={currentCard.questionImage} 
                    className="max-h-40 mb-4 rounded border shadow-sm"
                    onError={() => setImgError(true)}
                  />
                )}
                <div 
                  className="text-xl md:text-2xl font-bold text-center text-slate-800 leading-relaxed"
                  dangerouslySetInnerHTML={{ __html: currentCard.questionText }}
                />
              </div>
              <div className="h-8 text-center text-[10px] font-bold text-slate-300 uppercase tracking-widest">Click to reveal</div>
            </div>

            <div className="absolute inset-0 w-full h-full bg-slate-800 rounded-xl shadow-md border border-slate-700 backface-hidden rotate-y-180 flex flex-col overflow-hidden group-hover:shadow-2xl transition-shadow duration-500">
              <div className="px-6 pt-6 flex justify-between items-center">
                <span className="text-xs font-bold uppercase text-blue-400">Answer</span>
                <button 
                  onClick={(e) => speak(stripHtml(currentCard.answerText), currentCard.id, 'answer', e)}
                  className={`p-2 rounded-full transition-all ${isSpeaking && activeType === 'answer' ? 'text-blue-400 bg-white/10' : 'text-slate-500 hover:text-blue-400'}`}
                >
                  <Volume2 size={18} />
                </button>
              </div>
              <div className="flex-1 p-6 flex flex-col items-center justify-center overflow-y-auto">
                {currentCard.answerImage && !ansImgError && (
                  <img 
                    src={currentCard.answerImage} 
                    className="max-h-40 mb-4 rounded border border-slate-600"
                    onError={() => setAnsImgError(true)}
                  />
                )}
                <div 
                  className="text-xl md:text-3xl font-bold text-center text-white leading-relaxed mb-4"
                  dangerouslySetInnerHTML={{ __html: currentCard.answerText }}
                />
                {currentCard.explanation && (
                  <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700/50 text-slate-300 text-sm leading-relaxed max-w-lg text-center"
                    dangerouslySetInnerHTML={{ __html: currentCard.explanation }} 
                  />
                )}
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="p-12 bg-white rounded-xl border-2 border-dashed text-center">No cards found.</div>
      )}

      <div className="flex items-center gap-6 mt-8">
        <Button variant="outline" onClick={() => setCurrentIndex(p => Math.max(0, p-1))} disabled={currentIndex === 0} className="w-12 h-12 rounded-full"><ChevronLeft /></Button>
        <Button variant="primary" onClick={flipCard} className="h-12 px-8 rounded-full shadow-lg">
          {isFlipped ? 'Hide' : 'Reveal'}
        </Button>
        <Button variant="secondary" onClick={() => setCurrentIndex(p => Math.min(deck.length-1, p+1))} disabled={currentIndex === deck.length-1} className="w-12 h-12 rounded-full"><ChevronRight /></Button>
      </div>
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';
import { 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  SquareCheckBig, 
  LayoutGrid, 
  Image as ImageIcon, 
  Zap, 
  Hash, 
  Menu, 
  Filter, 
  Info, 
  CircleCheck, 
  CircleAlert, 
  Volume2, 
  VolumeX, 
  Lightbulb, 
  Eye, 
  EyeOff, 
  Settings, 
  Keyboard 
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'incorrect' | 'correct'>('all');
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);

  // History
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);

  // New Audio Hook
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  // Strip HTML for speech
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }
  }, []);

  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id);
        } else {
          newMistakes.add(q.id);
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  }, [view]);

  useEffect(() => {
    setImgError(false);
    cancel(); // Stop audio when moving to next question
  }, [currentQIndex, cancel]);

  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    return [...pool].sort(() => Math.random() - 0.5).slice(0, count).map(q => {
      const correct = q.answerText;
      let options: string[] = [];

      if (q.options && q.options.length > 0) {
        options = [...q.options].sort(() => Math.random() - 0.5);
        if (!options.includes(correct)) {
          options[0] = correct;
          options = options.sort(() => Math.random() - 0.5);
        }
      } else {
        const categoryDistractors = Array.from<string>(new Set(
          data
            .filter(i => i.category === q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        ));

        const generalDistractors = Array.from<string>(new Set(
          data
            .filter(i => i.category !== q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        ));

        let selectedDistractors: string[] = [];

        if (categoryDistractors.length >= 3) {
          selectedDistractors = categoryDistractors.sort(() => Math.random() - 0.5).slice(0, 3);
        } else {
          selectedDistractors = [...categoryDistractors];
          const needed = 3 - selectedDistractors.length;
          const extra = generalDistractors.sort(() => Math.random() - 0.5).slice(0, needed);
          selectedDistractors = [...selectedDistractors, ...extra];
        }

        options = [...selectedDistractors, correct].sort(() => Math.random() - 0.5);
      }

      return {
        id: q.id,
        data: q,
        options,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria. Please select more topics or disable the image filter.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60);
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Timer Tick Effect
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => Math.max(0, prev - 1));
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Timer Expiry Effect
  useEffect(() => {
    if (timeLeft === 0 && (view === 'playing' || view === 'review') && mode !== 'practice') {
      setView('results');
    }
  }, [timeLeft, view, mode]);

  const handleAnswer = (option: string) => {
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return;

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (view === 'playing' || view === 'review') {
        if (e.key === 'ArrowRight' && currentQIndex < questions.length - 1) {
          setCurrentQIndex(prev => prev + 1);
        } else if (e.key === 'ArrowLeft' && currentQIndex > 0) {
          setCurrentQIndex(prev => prev - 1);
        }

        if (view === 'playing' && ['1', '2', '3', '4'].includes(e.key)) {
          const index = parseInt(e.key) - 1;
          const options = questions[currentQIndex].options;
          if (index >= 0 && index < options.length) {
            handleAnswer(options[index]);
          }
        }
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [view, currentQIndex, questions]);

  const toggleFlag = () => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  if (view === 'setup') {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-4 md:p-8 bg-slate-50 pb-32 md:pb-8">
        <div className="w-full max-w-2xl bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-gradient-to-r from-slate-900 to-slate-800 p-6 text-white">
            <h1 className="text-2xl font-black uppercase tracking-tight mb-1 flex items-center gap-3">
              <LayoutGrid className="text-blue-400" /> Exam Portal
            </h1>
            <p className="text-slate-400 text-sm font-medium">Configure your session parameters.</p>
          </div>

          <div className="p-6 md:p-8 space-y-8">
            <div>
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 block">Select Mode</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'exam' ? 'border-red-600 bg-red-50 text-red-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Clock size={24} />
                  <div className="font-bold">Exam Mode</div>
                  <div className="text-[10px] opacity-75">Timed • Final Grade</div>
                </button>
                <button 
                  onClick={() => setMode('practice')}
                  className={`p-4 rounded-xl border-2 transition-all flex flex-col items-center text-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-200 hover:border-slate-300 text-slate-500'}`}
                >
                  <Zap size={24} />
                  <div className="font-bold">Practice Mode</div>
                  <div className="text-[10px] opacity-75">Instant Feedback</div>
                </button>
              </div>
            </div>

            {mistakesHistory.length > 0 && (
              <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-center justify-between animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                  <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                    <BrainCircuit size={20} />
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-amber-900 uppercase">Smart Review</h3>
                    <p className="text-xs text-amber-700 font-medium">{mistakesHistory.length} questions to master</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={clearMistakes} className="p-2 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                    <X size={18} />
                  </button>
                  <button onClick={startMistakesReview} className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-sm transition-colors">
                    <RotateCcw size={16} /> Retry Mistakes
                  </button>
                </div>
              </div>
            )}

            <div>
              <div className="flex justify-between items-center mb-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Filter Questions</label>
                {selectedGroups.length > 0 && (
                  <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    <X size={12} /> Clear Filters
                  </button>
                )}
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="w-full flex items-center justify-between p-3 bg-white border border-slate-300 rounded-lg hover:border-blue-400 transition-colors shadow-sm"
                >
                  <div className="flex items-center gap-2 text-slate-700 font-medium truncate">
                    <Filter size={18} className="text-slate-400" />
                    {selectedGroups.length === 0 ? `All Topics (${maxPossibleQuestions} Qs)` : `${selectedGroups.length} Topics Selected (${maxPossibleQuestions} Qs)`}
                  </div>
                  {isDropdownOpen ? <ChevronLeft className="rotate-90" size={18} /> : <ChevronRight className="rotate-90" size={18} />}
                </button>

                {isDropdownOpen && (
                  <div className="absolute top-full left-0 w-full mt-2 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500 uppercase">Select Topics</span>
                      <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700">
                        {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                      </button>
                    </div>
                    <div className="max-h-60 overflow-y-auto p-2 custom-scrollbar">
                      {availableGroups.map(group => (
                        <label key={group} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-lg cursor-pointer group">
                          <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                            <input 
                              type="checkbox" 
                              className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                              checked={selectedGroups.includes(group)}
                              onChange={() => toggleGroup(group)}
                            />
                            <Check size={12} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                          </div>
                          <span className="text-sm text-slate-700 font-medium group-hover:text-slate-900">{group}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {selectedGroups.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-3 p-3 bg-slate-50 border border-slate-100 rounded-lg max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                  {selectedGroups.map(group => (
                    <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                      {group}
                      <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                        <X size={12} />
                      </button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                    <Hash size={16} className="text-blue-500" /> Question Limit
                  </label>
                  <span className="text-xs font-bold text-slate-400 bg-white px-2 py-1 rounded border border-slate-200">Max: {maxPossibleQuestions}</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="relative w-24 shrink-0">
                    <input 
                      type="number" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount}
                      onChange={(e) => {
                        const val = parseInt(e.target.value);
                        if (!isNaN(val)) {
                          const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                          setQuestionCount(safeVal);
                        }
                      }}
                      className="w-full px-3 py-2 text-center text-xl font-black text-slate-800 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                  </div>
                  <div className="flex-1">
                    <input 
                      type="range" 
                      min="1" 
                      max={maxPossibleQuestions} 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                      className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                    />
                  </div>
                </div>
                <p className="text-[10px] text-slate-400 mt-2 text-center font-medium">Drag slider or type to set questions</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 flex flex-col justify-center gap-4">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-wide flex items-center gap-2">
                  <Settings size={16} className="text-blue-500" /> Display Options
                </label>

                <button 
                  onClick={() => setShowImagesOnly(!showImagesOnly)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm flex items-center gap-2"><ImageIcon size={16} /> Diagrams Only</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>

                <button 
                  onClick={() => setShowExplanations(!showExplanations)}
                  className={`w-full flex items-center justify-between p-3 rounded-lg border-2 transition-all ${showExplanations ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-300 bg-white text-slate-500 hover:border-blue-300'}`}
                >
                  <span className="font-bold text-sm flex items-center gap-2"><Lightbulb size={16} /> Show Explanations</span>
                  <div className={`w-11 h-6 rounded-full relative transition-colors ${showExplanations ? 'bg-blue-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 w-4 h-4 rounded-full bg-white transition-all shadow-sm ${showExplanations ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </button>
              </div>
            </div>

            <Button variant="primary" onClick={startQuiz} fullWidth className="py-4 text-lg shadow-xl shadow-red-200/50" disabled={maxPossibleQuestions === 0}>
              {maxPossibleQuestions === 0 ? 'No Questions Match Filter' : 'Start Assessment'}
            </Button>
          </div>
        </div>
      </div>
    );
  }

  // Results View
  if (view === 'results') {
    const score = calculateScore();
    const passed = score >= 60;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;

    const filteredQuestions = questions.filter(q => {
      const isCorrect = q.userAnswer === q.correctOption;
      if (filterType === 'correct') return isCorrect;
      if (filterType === 'incorrect') return !isCorrect;
      return true;
    });

    return (
      <div className="min-h-screen bg-slate-50 p-4 md:p-8 pb-24">
        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 mb-8">
            <div className="bg-slate-900 p-8 text-center relative overflow-hidden border-b-4 border-red-600">
              <div className="relative z-10">
                <h2 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">Assessment Complete</h2>
                <div className="flex items-center justify-center gap-8 mb-6">
                  <div>
                    <div className="text-6xl font-black text-white tracking-tighter">{score}%</div>
                    <div className="text-slate-400 text-xs font-bold uppercase tracking-wider mt-1">Final Score</div>
                  </div>
                  <div className="h-12 w-px bg-slate-700"></div>
                  <div className="text-left">
                    <div className={`text-2xl font-bold ${passed ? 'text-emerald-400' : 'text-red-400'}`}>
                      {passed ? 'PASSED' : 'FAILED'}
                    </div>
                    <div className="text-slate-400 text-sm font-medium">{correctCount} / {questions.length} Correct</div>
                    {mode === 'mistakes' && <div className="text-amber-400 text-xs font-bold uppercase mt-1">Mistakes Review Mode</div>}
                  </div>
                </div>
                <Button variant="outline" onClick={() => setView('setup')} className="bg-white/10 text-white border-white/20 hover:bg-white/20 hover:text-white hover:border-white/30">
                  Take Another Exam
                </Button>
              </div>
            </div>

            <div className="p-6 md:p-8 bg-slate-50">
              <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <CircleCheck className="text-blue-600" size={20} />
                  Answer Key
                </h3>

                <div className="flex flex-col sm:flex-row items-center gap-4">
                  <button
                    onClick={() => setShowExplanations(!showExplanations)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-all border ${
                      showExplanations 
                        ? 'bg-blue-50 text-blue-700 border-blue-200' 
                        : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
                    }`}
                  >
                    {showExplanations ? <Eye size={14} /> : <EyeOff size={14} />}
                    {showExplanations ? 'Hide Explanations' : 'Show Explanations'}
                  </button>

                  <div className="flex bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
                    {(['all', 'incorrect', 'correct'] as const).map((ft) => (
                      <button
                        key={ft}
                        onClick={() => setFilterType(ft)}
                        className={`px-4 py-1.5 rounded-md text-xs font-bold uppercase tracking-wide transition-all ${filterType === ft ? 'bg-slate-800 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
                      >
                        {ft}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {filteredQuestions.map((q, idx) => {
                  const isCorrect = q.userAnswer === q.correctOption;
                  const originalIndex = questions.findIndex(orig => orig.id === q.id);
                  return (
                    <div key={q.id} className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex gap-4">
                        <div className={`shrink-0 w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${isCorrect ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                          {originalIndex + 1}
                        </div>
                        <div className="flex-1">
                          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-2 mb-3">
                            {/* Question Text */}
                            <h4 
                              className="font-semibold text-slate-900 text-base md:text-lg"
                              dangerouslySetInnerHTML={{ __html: q.data.questionText }} 
                            />
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 bg-slate-100 px-2 py-1 rounded border border-slate-200 shrink-0 w-fit">
                              {q.data.category || 'General'}
                            </span>
                          </div>

                          {q.data.questionImage && (
                            <div className="mb-4 p-2 bg-slate-50 rounded border border-slate-100 inline-block min-w-[150px]">
                              <img src={q.data.questionImage} alt="question" className="h-32 object-contain rounded" />
                            </div>
                          )}

                          <div className="grid md:grid-cols-2 gap-4 mb-4">
                            <div className={`p-3 rounded-lg border text-sm ${isCorrect ? 'bg-emerald-50/50 border-emerald-200 text-emerald-900' : 'bg-red-50/50 border-red-200 text-red-900'}`}>
                              <span className="block text-xs font-bold opacity-70 mb-1 uppercase">Your Answer</span>
                              {q.userAnswer ? <span dangerouslySetInnerHTML={{ __html: q.userAnswer }} /> : "Skipped"}
                            </div>
                            {!isCorrect && (
                              <div className="p-3 rounded-lg border border-slate-200 bg-slate-50 text-slate-700 text-sm">
                                <span className="block text-xs font-bold opacity-50 mb-1 uppercase">Correct Answer</span>
                                <span dangerouslySetInnerHTML={{ __html: q.correctOption }} />
                              </div>
                            )}
                          </div>

                          {showExplanations && q.data.explanation && (
                            <div className="flex gap-3 p-4 bg-blue-50 rounded-lg border border-blue-100">
                              <Info className="shrink-0 text-blue-600 mt-0.5" size={18} />
                              <div>
                                <div className="flex justify-between items-center mb-1">
                                  <p className="text-xs font-bold text-blue-800 uppercase tracking-wide">Explanation</p>
                                  <button 
                                    onClick={() => speak(stripHtml(q.data.explanation || ''), q.id)} 
                                    className={`transition-all p-1 rounded ${isSpeaking && speakingId === q.id ? 'text-blue-700 bg-blue-100 ring-2 ring-blue-300 animate-pulse' : 'text-blue-500 hover:text-blue-700 hover:bg-blue-100'}`}
                                    title={isSpeaking && speakingId === q.id ? "Stop Reading" : "Read Explanation"}
                                  >
                                    {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                                  </button>
                                </div>
                                <p 
                                  className="text-sm text-slate-700 leading-relaxed"
                                  dangerouslySetInnerHTML={{ __html: q.data.explanation }}
                                />
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Review View
  if (view === 'review') {
    const answeredCount = questions.filter(q => q.userAnswer !== null).length;
    const flaggedCount = questions.filter(q => q.isFlagged).length;

    return (
      <div className="min-h-screen bg-slate-50 p-6 pb-32 flex flex-col items-center">
        <div className="max-w-3xl w-full bg-white rounded-xl shadow-xl border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 p-6 text-white flex justify-between items-center shadow-md">
            <div>
              <h2 className="text-xl font-bold">Review Answers</h2>
              <p className="text-slate-400 text-sm">Verify your progress before final submission.</p>
            </div>
            {mode !== 'practice' && (
              <div className="text-right bg-slate-700 px-4 py-2 rounded-lg border border-slate-600">
                <div className="font-mono text-lg font-bold text-white">{formatTime(timeLeft)}</div>
              </div>
            )}
          </div>

          <div className="p-6">
            <div className="flex justify-around mb-8 py-6 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-center">
                <div className="text-2xl font-black text-slate-800">{questions.length}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Total</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-blue-600">{answeredCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Answered</div>
              </div>
              <div className="w-px bg-slate-200"></div>
              <div className="text-center">
                <div className="text-2xl font-black text-amber-500">{flaggedCount}</div>
                <div className="text-[10px] font-bold uppercase text-slate-400 tracking-wider">Flagged</div>
              </div>
            </div>

            <div className="mb-8">
              <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-2">
                {questions.map((q, idx) => (
                  <button
                    key={q.id}
                    onClick={() => { setCurrentQIndex(idx); setView('playing'); }}
                    className={`
                      aspect-square flex flex-col items-center justify-center rounded-md text-sm font-bold border-2 transition-all relative hover:scale-105
                      ${q.isFlagged ? 'bg-amber-50 border-amber-400 text-amber-800' : 
                        q.userAnswer ? 'bg-blue-50 border-blue-500 text-blue-800' : 'bg-white border-slate-200 text-slate-400'}
                    `}
                  >
                    {idx + 1}
                    {q.isFlagged && <div className="w-2 h-2 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <Button variant="outline" fullWidth onClick={() => setView('playing')}>
                <ChevronLeft size={18} className="mr-2" /> Return
              </Button>
              <Button variant="primary" fullWidth onClick={() => setView('results')}>
                Submit Exam
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];
  const isPractice = mode === 'practice';
  const hasAnsweredPractice = isPractice && currentQ.userAnswer !== null;
  const optionLabels = ['A', 'B', 'C', 'D', 'E', 'F'];

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] bg-slate-50 overflow-hidden">
      <div className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <button 
            className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          >
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
          <div>
            <h2 className="text-slate-800 font-bold text-base md:text-lg flex items-center gap-2">
              {isPractice ? <Zap size={18} className="text-amber-500" /> : 
               mode === 'mistakes' ? <RotateCcw size={18} className="text-amber-600" /> :
               <Clock size={18} className="text-red-500" />}
              {isPractice ? 'Practice' : mode === 'mistakes' ? 'Review Mistakes' : 'Exam'}
            </h2>
            <p className="text-xs text-slate-400 font-medium hidden md:block">Question {currentQIndex + 1} of {questions.length}</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {mode !== 'practice' && (
            <div className={`flex items-center gap-2 px-4 py-2 rounded-lg font-mono font-bold text-sm border transition-colors shadow-sm ${
              timeLeft < 60 ? 'bg-red-50 text-red-600 border-red-200 animate-pulse' : 
              timeLeft < 300 ? 'bg-amber-50 text-amber-700 border-amber-200' : 
              'bg-white text-slate-700 border-slate-200'
            }`}>
              <Clock size={16} className={timeLeft < 60 ? 'animate-bounce' : ''} />
              {formatTime(timeLeft)}
            </div>
          )}
          <Button variant="primary" className="bg-slate-900 hover:bg-slate-800 text-xs md:text-sm px-3 md:px-5 h-9 md:h-10" onClick={() => setView(isPractice ? 'results' : 'review')}>
            {isPractice ? 'End' : 'Submit'}
          </Button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden relative">
        <aside className={`
          absolute md:static top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-10 transition-transform duration-300 transform
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 flex flex-col shadow-lg md:shadow-none
        `}>
          <div className="p-4 border-b border-slate-100 bg-slate-50">
            <span className="text-xs font-bold uppercase tracking-wider text-slate-500">Question Map</span>
          </div>
          <div className="p-4 grid grid-cols-4 gap-2 content-start overflow-y-auto flex-1 custom-scrollbar">
            {questions.map((q, idx) => {
              const isCurrent = idx === currentQIndex;
              const isAnswered = q.userAnswer !== null;
              const isFlagged = q.isFlagged;

              let classes = "bg-white text-slate-400 border-slate-200 hover:bg-slate-50 hover:border-slate-300";
              if (isCurrent) classes = "bg-slate-800 text-white border-slate-800 ring-2 ring-slate-200 z-10";
              else if (isFlagged) classes = "bg-amber-50 text-amber-700 border-amber-300";
              else if (isPractice && isAnswered) {
                classes = q.userAnswer === q.correctOption ? "bg-emerald-50 text-emerald-600 border-emerald-300" : "bg-red-50 text-red-600 border-red-300";
              }
              else if (isAnswered) classes = "bg-blue-50 text-blue-600 border-blue-200";

              return (
                <button
                  key={q.id}
                  onClick={() => { setCurrentQIndex(idx); setIsSidebarOpen(false); }}
                  className={`aspect-square rounded border-2 flex items-center justify-center text-xs font-bold transition-all relative ${classes}`}
                >
                  {idx + 1}
                  {isFlagged && !isCurrent && <div className="w-1.5 h-1.5 bg-amber-500 rounded-full absolute top-1 right-1"></div>}
                </button>
              );
            })}
          </div>
        </aside>

        <main className="flex-1 overflow-y-auto bg-slate-100 p-4 md:p-8 scroll-smooth pb-32 md:pb-8 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col relative min-h-[60vh]">
              <div className="w-full h-1.5 bg-slate-100">
                <div 
                  className="h-full bg-red-600 transition-all duration-300" 
                  style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                ></div>
              </div>

              <div className="p-6 md:p-10 flex-1">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500 bg-slate-100 px-2 py-1 rounded w-fit border border-slate-200">
                      {currentQ.data.category || 'General Knowledge'}
                    </span>
                    <div className="hidden md:flex items-center gap-2 text-[10px] text-slate-400 font-medium mt-1">
                      <Keyboard size={12} />
                      <span>Use keys 1-4 to select</span>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {mode !== 'exam' && (
                      <button 
                        onClick={() => speak(stripHtml(currentQ.data.questionText), 'main-question')}
                        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-all border ${isSpeaking && speakingId === 'main-question' ? 'bg-blue-50 border-blue-300 text-blue-700 ring-2 ring-blue-200 animate-pulse' : 'bg-white border-slate-200 text-slate-400 hover:text-blue-600 hover:border-blue-200'}`}
                        title={isSpeaking && speakingId === 'main-question' ? "Stop Reading" : "Read Question"}
                      >
                        {isSpeaking && speakingId === 'main-question' ? <VolumeX size={14} /> : <Volume2 size={14} />}
                        {isSpeaking && speakingId === 'main-question' ? 'Stop' : 'Speak'}
                      </button>
                    )}
                    <button 
                      onClick={toggleFlag}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border ${currentQ.isFlagged ? 'bg-amber-50 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-600'}`}
                    >
                      <Flag size={14} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                      {currentQ.isFlagged ? 'Flagged' : 'Flag'}
                    </button>
                  </div>
                </div>

                {/* Render Question as HTML */}
                <h2 
                  className="text-xl md:text-2xl font-bold text-slate-900 leading-snug mb-8"
                  dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }}
                />

                <div className="flex flex-col lg:flex-row gap-8">
                  {/* OPTIONS CONTAINER: Converted to Grid for compaction */}
                  <div className={`flex-1 grid grid-cols-1 md:grid-cols-2 gap-3 auto-rows-fr order-2 ${currentQ.data.questionImage ? 'lg:order-1' : ''}`}>
                    {currentQ.options.map((option, idx) => {
                      const isSelected = currentQ.userAnswer === option;
                      const isCorrect = option === currentQ.correctOption;

                      let containerClass = "border-slate-200 bg-white hover:border-blue-300 hover:bg-slate-50 text-slate-700 shadow-sm";
                      let labelClass = "bg-slate-100 text-slate-500 border-slate-200";

                      if (hasAnsweredPractice) {
                        if (isCorrect) {
                          containerClass = "border-emerald-500 bg-emerald-50/50 ring-1 ring-emerald-500 text-emerald-900";
                          labelClass = "bg-emerald-200 text-emerald-800 border-emerald-300";
                        } else if (isSelected && !isCorrect) {
                          containerClass = "border-red-500 bg-red-50/50 ring-1 ring-red-500 text-red-900";
                          labelClass = "bg-red-200 text-red-800 border-red-300";
                        } else {
                          containerClass = "border-slate-200 opacity-60";
                        }
                      } else if (isSelected) {
                        containerClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600 text-blue-900 shadow-md transform scale-[1.01]";
                        labelClass = "bg-blue-600 text-white border-blue-600";
                      }

                      return (
                        <button
                          key={idx}
                          onClick={() => handleAnswer(option)}
                          disabled={hasAnsweredPractice}
                          className={`w-full h-full text-left p-3 md:p-4 rounded-xl border-2 transition-all flex items-center gap-4 group relative ${containerClass}`}
                        >
                          <div className={`shrink-0 w-8 h-8 md:w-10 md:h-10 flex items-center justify-center rounded-lg font-bold text-sm md:text-base border ${labelClass} transition-colors`}>
                            {optionLabels[idx]}
                          </div>

                          {/* Render Option as HTML */}
                          <span 
                            className="font-medium text-base leading-snug flex-1 pr-8"
                            dangerouslySetInnerHTML={{ __html: option }}
                          />

                          {mode === 'practice' && (
                            <div 
                              role="button"
                              tabIndex={0}
                              onClick={(e) => { e.stopPropagation(); speak(stripHtml(option), `opt-${idx}`); }}
                              className={`absolute right-3 p-2 rounded-full transition-all opacity-0 group-hover:opacity-100 focus:opacity-100 ${isSpeaking && speakingId === `opt-${idx}` ? 'opacity-100 text-blue-600 bg-blue-100 ring-2 ring-blue-300 animate-pulse' : 'text-slate-400 hover:text-blue-600 hover:bg-slate-100'}`}
                              title="Listen to option"
                            >
                              {isSpeaking && speakingId === `opt-${idx}` ? <VolumeX size={16} /> : <Volume2 size={16} />}
                            </div>
                          )}
                        </button>
                      );
                    })}

                    {/* Explanation Box (Full Width in Grid) */}
                    {hasAnsweredPractice && (
                      <div className="md:col-span-2 mt-2 animate-in fade-in slide-in-from-top-2 duration-300">
                        <div className={`border-l-4 rounded-r-lg p-5 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-blue-50 border-blue-500'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <div className="flex items-center gap-2">
                              {currentQ.userAnswer === currentQ.correctOption ? 
                                <span className="text-emerald-800 font-bold text-sm uppercase flex items-center gap-2"><CircleCheck size={16} /> Correct</span> :
                                <span className="text-blue-800 font-bold text-sm uppercase flex items-center gap-2"><Info size={16} /> Explanation</span>
                              }
                            </div>
                            <button 
                              onClick={() => speak(stripHtml(currentQ.data.explanation || 'No explanation available.'), 'main-explanation')}
                              className={`transition-all rounded p-1 ${isSpeaking && speakingId === 'main-explanation' ? 'text-blue-800 bg-blue-200 ring-2 ring-blue-300 animate-pulse' : 'text-slate-400 hover:text-slate-600'}`}
                              title="Read Explanation"
                            >
                              {isSpeaking && speakingId === 'main-explanation' ? <VolumeX size={16} /> : <Volume2 size={16} />}
                            </button>
                          </div>
                          <p 
                            className="text-slate-700 text-sm leading-relaxed"
                            dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "No explanation available for this question." }}
                          />
                        </div>
                      </div>
                    )}
                  </div>

                  {currentQ.data.questionImage && (
                    <div className="lg:w-2/5 order-1 lg:order-2">
                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-2 flex items-center justify-center shadow-inner h-full min-h-[200px]">
                        {imgError ? (
                          <div className="flex flex-col items-center justify-center p-8 text-slate-400 gap-2 h-64">
                            <CircleAlert size={32} />
                            <span className="text-sm font-semibold">Image unavailable</span>
                          </div>
                        ) : (
                          <img 
                            src={currentQ.data.questionImage} 
                            alt="Diagram" 
                            className="max-h-64 object-contain rounded" 
                            onError={() => setImgError(true)}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
                <Button 
                  variant="ghost" 
                  disabled={currentQIndex === 0}
                  onClick={() => setCurrentQIndex(prev => prev - 1)}
                >
                  <ChevronLeft size={18} className="mr-2" /> Previous
                </Button>

                {currentQIndex < questions.length - 1 ? (
                  <Button 
                    variant="secondary" 
                    onClick={() => setCurrentQIndex(prev => prev + 1)}
                    className="px-6 shadow-lg shadow-blue-200/50"
                  >
                    Next Question <ChevronRight size={18} className="ml-2" />
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={() => setView(isPractice ? 'results' : 'review')}
                    className="px-6 shadow-lg shadow-red-200/50"
                  >
                    Finish <SquareCheckBig size={18} className="ml-2" />
                  </Button>
                )}
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle, Terminal
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    // Logic to ensure a valid key is selected for Pro models
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Neural Engine...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Authenticating Secure API Link...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Navigating Web Sources...' : 'Analyzing Anatomical Data...');

      const prompt = isUrl 
        ? `TASK: Web Content Extraction.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE professional anatomical quiz question based exclusively on the content of this page.

           REQUIRED OUTPUT FORMAT (JSON ONLY):
           {
             "questionText": "Clear question using <b> for key terms",
             "answerText": "Precise correct answer",
             "explanation": "Scientific rationale formatted with HTML tags",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "Identify the anatomical system/chapter",
             "questionImage": "Direct URL to a relevant image on the page if found"
           }`
        : `TASK: Text/HTML Synthesis.
           INPUT: """${rawInput}"""
           INSTRUCTION: Extract one anatomical quiz question from the provided input. 

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          // If using URL/Search, responseMimeType is often ignored by the grounding layer
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          // Only provide schema for non-URL as search grounding is less stable with complex configs
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Validating Structured Output...');

      // Grounding Source Extraction
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      // Robust JSON Extraction via Regex (essential for search results which often include fluff)
      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON architecture found in model response.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        // Shuffle options so correct isn't always first if the model was lazy
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Success! Rendering Preview...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Architectural Failure:", error);
      setIsAiLoading(false);

      if (error.message?.includes("Requested entity was not found")) {
        alert("CRITICAL ERROR: A paid API key from a Google Cloud Project is required for web-scraping features. Please select one now.");
        if (window.aistudio) await window.aistudio.openSelectKey();
      } else {
        alert("The AI Architect encountered an error. This usually happens if the URL is blocked or the content is too sparse. Try pasting the text directly.");
      }
    }
  };

  const generateDistractors = async () => {
    if (!formData.questionText || !formData.answerText) {
      alert("Please ensure the Question and Correct Answer fields are filled first.");
      return;
    }

    setIsAiLoading(true);
    setLoadingStep('Fabricating Neural Distractors...');

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `GENERATE DISTRACTORS.
                   Context: Anatomy & Physiology.
                   Question: "${formData.questionText}"
                   Correct Answer: "${formData.answerText}"

                   Task: Create 3 plausible but incorrect options (distractors) to complete the multiple choice set.
                   Return JSON: { "distractors": ["Option A", "Option B", "Option C"] }`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              distractors: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          }
        }
      });

      const json = JSON.parse(response.text || "{}");
      if (json.distractors && Array.isArray(json.distractors)) {
        // Combine correct answer with new distractors and shuffle
        const newOptions = [formData.answerText, ...json.distractors].sort(() => Math.random() - 0.5);
        setFormData(prev => ({ ...prev, options: newOptions }));
      }

      setIsAiLoading(false);
      setLoadingStep('');
    } catch (error) {
      console.error(error);
      setIsAiLoading(false);
      alert("AI Generation failed. Please try again.");
    }
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) {
        alert("Submission Failed: Question and Answer are required fields.");
        return;
    }

    // VALIDATION: Check for empty or missing options
    const filledOptions = formData.options.filter(o => o && o.trim().length > 0);

    if (filledOptions.length < 2) {
       const confirmGen = confirm("Security Alert: Insufficient options detected. This question is incomplete. \n\nWould you like the AI Architect to auto-generate distractors for you?");
       if (confirmGen) {
           generateDistractors();
           return;
       } else {
           // If user declines AI, refuse to save invalid data
           return;
       }
    }

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData,
      options: filledOptions // Ensure we don't save empty strings
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-12 space-y-12 pb-48 animate-in fade-in duration-1000">

      {/* PHASE 1: THE INPUT COMMAND CENTER */}
      {!showPreview && (
        <div className="relative max-w-5xl mx-auto pt-4">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full bg-blue-600/10 rounded-full blur-[160px] pointer-events-none"></div>

          <div className="relative bg-slate-900 rounded-[3.5rem] shadow-[0_40px_100px_rgba(0,0,0,0.5)] border border-slate-800/80 backdrop-blur-2xl overflow-hidden">
            <div className="p-8 md:p-20 space-y-12">

              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10">
                <div className="space-y-4">
                  <div className="flex items-center gap-5">
                    <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl shadow-2xl flex items-center justify-center text-white ring-4 ring-blue-500/20 transform rotate-3">
                      <Zap size={32} className="animate-pulse" />
                    </div>
                    <div>
                      <h2 className="text-4xl md:text-6xl font-black text-white tracking-tighter leading-none">
                        AI <span className="text-blue-500">Architect</span>
                      </h2>
                      <p className="text-slate-500 font-bold text-xs uppercase tracking-[0.4em] mt-3">Professional Data Extraction Suite</p>
                    </div>
                  </div>
                </div>

                <div className="hidden md:flex items-center gap-4 bg-slate-950/50 p-4 rounded-3xl border border-slate-800/50">
                   <div className="flex flex-col items-end">
                      <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">Neural Link: Active</span>
                      <span className="text-xs font-bold text-slate-300">Gemini 3 Pro + Search</span>
                   </div>
                   <div className="w-12 h-12 rounded-2xl border-2 border-slate-800 flex items-center justify-center bg-slate-900 shadow-inner">
                      <div className="w-3 h-3 bg-emerald-500 rounded-full shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-ping"></div>
                   </div>
                </div>
              </div>

              <div className="relative group">
                {isAiLoading && (
                  <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-md rounded-[2.5rem] border-2 border-blue-500/30 animate-in zoom-in-95 duration-300">
                    <div className="relative">
                      <div className="w-24 h-24 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Cpu className="text-blue-400 animate-pulse" size={32} />
                      </div>
                    </div>
                    <div className="mt-8 text-center space-y-3">
                      <p className="text-xl font-black text-white tracking-tight">{loadingStep}</p>
                      <div className="flex items-center gap-2 justify-center">
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></span>
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                      </div>
                    </div>
                  </div>
                )}

                <div className="absolute -inset-2 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2.5rem] blur opacity-10 group-hover:opacity-20 transition duration-1000"></div>

                <div className="relative">
                  <textarea
                    value={rawInput}
                    onChange={(e) => setRawInput(e.target.value)}
                    className="w-full h-80 p-12 bg-slate-950/60 text-blue-50 rounded-[2.5rem] border-2 border-slate-800 focus:border-blue-500 outline-none font-medium text-2xl placeholder:text-slate-700 transition-all shadow-inner resize-none custom-scrollbar"
                    placeholder="Paste URL (e.g. kenhub.com/en/skull) or copy-paste anatomy notes here..."
                  />
                  <div className="absolute bottom-6 right-8 flex items-center gap-2 text-slate-700 font-black text-[10px] uppercase tracking-widest pointer-events-none">
                    <Terminal size={14} /> Neural Input Interface v4.2
                  </div>
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-8 mt-10">
                  <div className="flex items-center gap-10">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Grounding Tool</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2 mt-1">
                        <Globe size={16} className="text-blue-500" /> Web-to-Vault Sync
                      </span>
                    </div>
                    <div className="w-px h-10 bg-slate-800"></div>
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Output Logic</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2 mt-1">
                        <FileCode size={16} className="text-indigo-500" /> Structural JSON
                      </span>
                    </div>
                  </div>

                  <button 
                    onClick={processEverythingWithAI}
                    disabled={isAiLoading || !rawInput.trim()}
                    className="w-full md:w-auto flex items-center justify-center gap-5 px-16 py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-3xl hover:bg-blue-500 hover:-translate-y-2 transition-all shadow-[0_20px_60px_rgba(37,99,235,0.4)] disabled:opacity-20 active:scale-95 group relative overflow-hidden"
                  >
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                    <Wand2 size={36} className="group-hover:rotate-12 transition-transform" />
                    <span>Generate Question</span>
                  </button>
                </div>
              </div>
            </div>

            <div className="h-2.5 bg-gradient-to-r from-blue-600 via-indigo-600 to-blue-600"></div>
          </div>

          <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-8">
             <div className="flex items-start gap-4 p-8 bg-white/5 rounded-3xl border border-slate-200/10">
                <ShieldCheck className="text-blue-500 shrink-0" size={24} />
                <div>
                  <h4 className="text-white font-bold text-sm uppercase tracking-wider mb-2">Verified Content</h4>
                  <p className="text-slate-500 text-xs leading-relaxed">Every question is processed through clinical validation layers to ensure anatomical precision.</p>
                </div>
             </div>
             <div className="flex items-start gap-4 p-8 bg-white/5 rounded-3xl border border-slate-200/10">
                <Database className="text-indigo-500 shrink-0" size={24} />
                <div>
                  <h4 className="text-white font-bold text-sm uppercase tracking-wider mb-2">Auto-Vaulting</h4>
                  <p className="text-slate-500 text-xs leading-relaxed">Generated data is instantly mirrored to your encrypted local vault for offline study capability.</p>
                </div>
             </div>
             <div className="flex items-start gap-4 p-8 bg-white/5 rounded-3xl border border-slate-200/10">
                <Zap className="text-amber-500 shrink-0" size={24} />
                <div>
                  <h4 className="text-white font-bold text-sm uppercase tracking-wider mb-2">Fast Synthesis</h4>
                  <p className="text-slate-500 text-xs leading-relaxed">Gemini 3 Turbo engines synthesize complex clinical scenarios from raw URLs in under 5 seconds.</p>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* PHASE 2: THE PUBLISHING AND REVIEW STAGE */}
      {showPreview && (
        <div className="max-w-6xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-20 duration-1000">

          <div className="flex flex-col md:flex-row justify-between items-center gap-8 bg-white p-8 rounded-[3rem] border border-slate-200 shadow-2xl">
            <div className="flex items-center gap-6">
              <button 
                onClick={resetSystem} 
                className="w-16 h-16 rounded-2xl bg-slate-50 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all flex items-center justify-center shadow-inner"
                title="Discard Blueprint"
              >
                <RotateCcw size={28} />
              </button>
              <div className="h-12 w-px bg-slate-100"></div>
              <div>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">Blueprint Review</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Staging Area: Pending Vault Publish</p>
              </div>
            </div>

            <div className="flex items-center gap-5 w-full md:w-auto">
              <button 
                onClick={() => setIsManualEdit(!isManualEdit)} 
                className={`flex-1 md:flex-none px-10 py-5 rounded-[1.5rem] font-black text-base transition-all flex items-center justify-center gap-3 border-2 ${isManualEdit ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-500'}`}
              >
                {isManualEdit ? <Eye size={22} /> : <Edit3 size={22} />}
                {isManualEdit ? 'Render View' : 'Manual Overrides'}
              </button>

              <button 
                onClick={handleGlobalPublish}
                className="flex-1 md:flex-none px-14 py-5 bg-emerald-600 text-white font-black text-base uppercase tracking-[0.25em] rounded-[1.5rem] shadow-[0_20px_50px_rgba(16,185,129,0.3)] hover:bg-emerald-500 hover:-translate-y-2 transition-all flex items-center justify-center gap-4 active:scale-95"
              >
                <Send size={22} />
                Publish to Vault
              </button>
            </div>
          </div>

          {sources.length > 0 && (
            <div className="bg-blue-600 text-white p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden">
               <div className="absolute top-0 right-0 p-10 opacity-10 -rotate-12">
                  <Globe size={180} />
               </div>
               <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
                  <div className="space-y-1">
                    <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-60">Search Grounding Metadata</span>
                    <h4 className="text-xl font-black tracking-tight">Verified Web Citations</h4>
                  </div>
                  <div className="flex flex-wrap gap-4">
                    {sources.map((s, idx) => (
                      <a 
                        key={idx} 
                        href={s.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center gap-3 px-6 py-3 bg-white/10 hover:bg-white/20 rounded-2xl border border-white/20 text-sm font-bold transition-all backdrop-blur-sm"
                      >
                        <ExternalLink size={16} />
                        {s.title}
                      </a>
                    ))}
                  </div>
               </div>
            </div>
          )}

          <div className="grid lg:grid-cols-12 gap-12">
            <div className="lg:col-span-8">
              {isManualEdit ? (
                <div className="bg-white rounded-[4rem] p-12 md:p-16 border border-slate-100 shadow-2xl space-y-12">
                  <div className="grid gap-10">
                    <div className="space-y-4">
                      <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                        <Layers size={18} className="text-blue-500" /> Classification
                      </div>
                      <input 
                        type="text" 
                        value={formData.category} 
                        onChange={e => setFormData({...formData, category: e.target.value})}
                        className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black text-2xl text-slate-800 outline-none focus:border-blue-500 transition-all shadow-inner"
                        placeholder="System or Chapter Title"
                      />
                    </div>

                    <div className="space-y-4">
                      <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                        <Terminal size={18} className="text-blue-500" /> Question Payload (HTML)
                      </div>
                      <textarea 
                        value={formData.questionText} 
                        onChange={e => setFormData({...formData, questionText: e.target.value})}
                        className="w-full h-56 p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] font-mono text-lg text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all shadow-inner"
                      />
                    </div>

                    <div className="grid sm:grid-cols-2 gap-8">
                      {formData.options.map((opt, i) => (
                        <div key={i} className="space-y-3">
                          <label className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em] px-3 flex justify-between">
                            <span>Index {String.fromCharCode(65 + i)}</span>
                            {opt === formData.answerText && <span className="text-emerald-500">Correct Target</span>}
                          </label>
                          <input 
                            type="text" 
                            value={opt} 
                            onChange={e => {
                              const newOpts = [...formData.options];
                              newOpts[i] = e.target.value;
                              setFormData({...formData, options: newOpts});
                            }}
                            className={`w-full p-5 rounded-2xl font-bold text-lg outline-none transition-all shadow-sm ${opt === formData.answerText ? 'bg-emerald-50 border-2 border-emerald-200 text-emerald-900' : 'bg-slate-50 border-2 border-slate-100 text-slate-700 focus:border-blue-500'}`}
                          />
                        </div>
                      ))}
                    </div>

                    <button 
                      type="button"
                      onClick={generateDistractors}
                      disabled={isAiLoading}
                      className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold uppercase tracking-widest text-xs flex items-center justify-center gap-2 transition-all shadow-lg hover:shadow-indigo-200"
                    >
                      {isAiLoading ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} />} 
                      Auto-Fill Distractors (AI)
                    </button>

                    <div className="space-y-4">
                      <div className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">
                        <Beaker size={18} className="text-blue-500" /> Scientific Core Rationale
                      </div>
                      <textarea 
                        value={formData.explanation} 
                        onChange={e => setFormData({...formData, explanation: e.target.value})}
                        className="w-full h-56 p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] font-mono text-lg text-slate-700 outline-none focus:border-blue-500 custom-scrollbar transition-all shadow-inner"
                      />
                    </div>
                  </div>
                </div>
              ) : (
                <div className="bg-white rounded-[4rem] shadow-[0_60px_150px_rgba(0,0,0,0.1)] border border-slate-100 overflow-hidden flex flex-col group transition-all duration-700 hover:shadow-[0_80px_200px_rgba(0,0,0,0.12)]">
                  <div className="bg-slate-950 p-10 flex justify-between items-center">
                    <span className="text-xs font-black text-blue-400 uppercase tracking-[0.5em] font-mono flex items-center gap-3">
                       <ShieldCheck size={18} className="animate-pulse" /> Data Matrix V4
                    </span>
                    <div className="flex items-center gap-3">
                       <span className="w-2.5 h-2.5 rounded-full bg-slate-800"></span>
                       <span className="w-2.5 h-2.5 rounded-full bg-slate-800"></span>
                       <span className="w-2.5 h-2.5 rounded-full bg-slate-800"></span>
                    </div>
                  </div>

                  <div className="p-12 md:p-24 space-y-16">
                    <div className="space-y-10">
                       <div className="px-8 py-3 bg-blue-50 rounded-2xl w-fit border-2 border-blue-100 shadow-sm">
                          <span className="text-sm font-black text-blue-600 uppercase tracking-widest">{formData.category}</span>
                       </div>

                       {formData.questionImage && (
                         <div className="w-full flex justify-center mb-10">
                           <div className="relative group/img">
                             <div className="absolute -inset-4 bg-blue-500/20 rounded-[3rem] blur-3xl opacity-0 group-hover/img:opacity-100 transition duration-700"></div>
                             <img 
                               src={formData.questionImage} 
                               alt="Architected Asset" 
                               className="relative max-h-96 rounded-[2rem] border-4 border-slate-100 shadow-2xl object-contain bg-white p-2"
                               onError={(e) => (e.currentTarget.style.display = 'none')}
                             />
                           </div>
                         </div>
                       )}

                       <h3 className="text-4xl md:text-6xl font-black text-slate-900 leading-tight tracking-tighter" dangerouslySetInnerHTML={{ __html: formData.questionText }} />
                    </div>

                    <div className="grid gap-6">
                      {formData.options.map((opt, i) => (
                        <div key={i} className={`p-8 rounded-[2.5rem] border-4 flex items-center gap-8 transition-all duration-500 ${opt === formData.answerText ? 'border-emerald-500 bg-emerald-50/50 shadow-xl shadow-emerald-100' : 'border-slate-50 bg-slate-50/30 text-slate-400'}`}>
                          <div className={`w-16 h-16 rounded-3xl flex items-center justify-center font-black text-3xl shadow-lg ${opt === formData.answerText ? 'bg-emerald-600 text-white' : 'bg-white border-2 border-slate-100 text-slate-300'}`}>
                            {String.fromCharCode(65 + i)}
                          </div>
                          <div className="font-bold text-3xl text-slate-800 tracking-tight" dangerouslySetInnerHTML={{ __html: opt }} />
                          {opt === formData.answerText && <CheckCircle2 className="ml-auto text-emerald-600 animate-in zoom-in duration-500" size={48} />}
                        </div>
                      ))}
                    </div>

                    <div className="bg-slate-950 rounded-[4rem] p-16 text-white/90 relative overflow-hidden shadow-3xl">
                       <div className="absolute top-0 right-0 p-12 text-blue-500/5 rotate-12">
                          <Database size={240} />
                       </div>
                       <div className="relative z-10 space-y-8">
                          <div className="flex items-center gap-4">
                             <div className="p-3 bg-blue-600 rounded-2xl shadow-xl">
                                <Zap size={24} className="text-white" />
                             </div>
                             <span className="text-lg font-black uppercase tracking-[0.3em] text-blue-400">Scientific Correlation</span>
                          </div>
                          <div className="text-2xl leading-relaxed font-medium prose prose-invert opacity-95 tracking-tight" dangerouslySetInnerHTML={{ __html: formData.explanation }} />
                       </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="lg:col-span-4 space-y-12">
              <div className="bg-white rounded-[3.5rem] p-12 border border-slate-100 shadow-3xl space-y-16 sticky top-36">
                <div className="space-y-10">
                  <h4 className="font-black text-slate-900 uppercase tracking-[0.3em] text-xs border-b border-slate-100 pb-8 flex items-center gap-3">
                    <ImageIcon size={20} className="text-blue-500" /> Digital Assets
                  </h4>

                  <div className="space-y-10">
                    <div className="space-y-4">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] px-2">Primary Asset Layer</label>
                      <div className="relative group/input">
                        <LinkIcon size={20} className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within/input:text-blue-500 transition-colors" />
                        <input 
                          type="url" 
                          value={formData.questionImage}
                          onChange={e => setFormData({...formData, questionImage: e.target.value})}
                          className="w-full pl-16 pr-8 py-6 rounded-2xl bg-slate-50 border-2 border-slate-50 text-xs font-bold text-slate-600 focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
                          placeholder="Diagram URL (Primary)"
                        />
                      </div>
                    </div>
                    <div className="space-y-4">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] px-2">Insight Detail Layer</label>
                      <div className="relative group/input">
                        <LinkIcon size={20} className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within/input:text-blue-500 transition-colors" />
                        <input 
                          type="url" 
                          value={formData.answerImage}
                          onChange={e => setFormData({...formData, answerImage: e.target.value})}
                          className="w-full pl-16 pr-8 py-6 rounded-2xl bg-slate-50 border-2 border-slate-50 text-xs font-bold text-slate-600 focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
                          placeholder="Clinical Visualization URL"
                        />
                      </div>
                    </div>
                  </div>
                </div>

                <div className="p-10 bg-gradient-to-br from-slate-900 to-slate-950 rounded-[3rem] text-white space-y-8 shadow-2xl relative overflow-hidden border border-slate-800">
                   <div className="absolute top-0 right-0 w-48 h-48 bg-blue-600/10 rounded-full blur-3xl -mr-24 -mt-24"></div>
                   <div className="flex items-center gap-5">
                      <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center shadow-2xl ring-4 ring-white/5">
                        <Server size={30} />
                      </div>
                      <div>
                        <span className="block font-black uppercase text-sm tracking-[0.2em]">Neural Auditor</span>
                        <span className="text-xs text-blue-400 font-bold">Precision Mapping: 100%</span>
                      </div>
                   </div>
                   <div className="space-y-4 pt-4 border-t border-white/5">
                      <div className="flex justify-between text-xs font-black uppercase tracking-widest text-slate-500">
                        <span>Clinical Terminology</span>
                        <span className="text-emerald-400">AUTHENTICATED</span>
                      </div>
                      <div className="h-2 bg-slate-800 rounded-full overflow-hidden shadow-inner">
                        <div className="h-full bg-blue-500 w-full shadow-[0_0_10px_rgba(59,130,246,0.5)]"></div>
                      </div>
                   </div>
                </div>

                <div className="flex items-start gap-5 p-8 bg-blue-50 rounded-[2.5rem] border-2 border-blue-100 shadow-sm">
                   <Info className="text-blue-600 shrink-0 mt-1" size={24} />
                   <p className="text-xs leading-relaxed text-blue-900 font-bold uppercase tracking-tight opacity-80">
                     Blueprint sync is operational. Publishing will update the Global Anatomical Registry across all synced devices.
                   </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default QuestionBuilder;
